            if (stat != 0) return LOG_RTERR (pctxt, stat);

            Asn1NamedEventHandler::invokeEndElement (pctxt, "xN", -1);

            RTXCTXTPOPELEMNAME (pctxt);

            break;

         /* f1 */
         case 2:
            RTXCTXTPUSHELEMNAME (pctxt, "f1");

            Asn1NamedEventHandler::invokeStartElement (pctxt, "f1", -1);
            pvalue->u.f1 = rtxMemAllocType (pctxt, ASN1T_InterfaceID_F1);

